import React, { useEffect, useState } from 'react';
// Importe StatusBadge e formatDate se necessário
// import StatusBadge from '...';
// import { formatDate } from '...';

const th = { textAlign: 'left', borderBottom: '1px solid #e5e7eb', padding: '8px 6px' };
const td = { borderBottom: '1px solid #f3f4f6', padding: '10px 6px', verticalAlign: 'top' };

export default function Adoptions() {
  const [statusFilter, setStatusFilter] = useState('all');
  const [adoptions, setAdoptions] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [page, setPage] = useState(1);
  const [pages, setPages] = useState(1);

  // Exemplo de função load
  const load = async (p = 1, status = statusFilter) => {
    setLoading(true);
    setError('');
    try {
      // Aqui você faria a requisição para buscar as adoções
      // const res = await fetch(...);
      // setAdoptions(res.data);
      // setPages(res.pages);
    } catch (e) {
      setError('Erro ao carregar adoções');
    }
    setLoading(false);
    setPage(p);
  };

  // Exemplo de função updateStatus
  const updateStatus = async (id, status) => {
    setLoading(true);
    setError('');
    try {
      // Atualize o status da adoção
      // await fetch(...);
      load(page, statusFilter);
    } catch (e) {
      setError('Erro ao atualizar status');
    }
    setLoading(false);
  };

  // Exemplo de formatDate
  const formatDate = (date) => {
    if (!date) return '—';
    return new Date(date).toLocaleDateString();
  };

  useEffect(() => {
    load(page, statusFilter);
    // eslint-disable-next-line
  }, [statusFilter]);

  return (
    <div>
      <div style={{ display: 'flex', gap: 12, alignItems: 'center', marginBottom: 16 }}>
        <label>Status:</label>
        <select value={statusFilter} onChange={(e) => setStatusFilter(e.target.value)}>
          <option value="all">Todos</option>
          <option value="pendente">Pendente</option>
          <option value="em análise">Em análise</option>
          <option value="aprovado">Aprovado</option>
          <option value="rejeitado">Rejeitado</option>
        </select>
        <div style={{ marginLeft: 'auto' }}>
          <button onClick={() => load(1, statusFilter)} disabled={loading}>Recarregar</button>
        </div>
      </div>

      {error && (
        <div style={{ background: '#fee2e2', color: '#991b1b', padding: 12, borderRadius: 8, marginBottom: 12 }}>
          {error}
        </div>
      )}

      <div style={{ overflowX: 'auto' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr>
              <th style={th}>Animal</th>
              <th style={th}>Adotante</th>
              <th style={th}>Contato</th>
              <th style={th}>Status</th>
              <th style={th}>Solicitação</th>
              <th style={th}>Ações</th>
            </tr>
          </thead>
          <tbody>
            {(adoptions ?? []).map((ad) => (
              <tr key={ad.id}>
                <td style={td}>{ad?.animal?.name ?? '—'}</td>
                <td style={td}>{ad?.adopter?.name ?? ad?.adopterName ?? '—'}</td>
                <td style={td}>
                  {ad?.adopter?.email ?? ad?.adopterEmail ?? '—'}
                  <br />
                  {ad?.adopter?.phone ?? ad?.adopterPhone ?? '—'}
                </td>
                <td style={td}>{/* <StatusBadge status={ad?.status} /> */ ad?.status ?? '—'}</td>
                <td style={td}>{formatDate(ad?.createdAt)}</td>
                <td style={td}>
                  <div style={{ display: 'flex', gap: 8 }}>
                    <button onClick={() => updateStatus(ad.id, 'aprovado')}>Aprovar</button>
                    <button onClick={() => updateStatus(ad.id, 'rejeitado')}>Rejeitar</button>
                  </div>
                </td>
              </tr>
            ))}
            {(!loading && (adoptions ?? []).length === 0) && (
              <tr><td colSpan={6} style={{ ...td, textAlign: 'center' }}>Nenhuma solicitação</td></tr>
            )}
          </tbody>
        </table>
      </div>

      <div style={{ display: 'flex', justifyContent: 'center', gap: 12, marginTop: 16 }}>
        <button disabled={page <= 1 || loading} onClick={() => load(page - 1)}>&lt; Anterior</button>
        <span>Página {page} de {pages}</span>
        <button disabled={page >= pages || loading} onClick={() => load(page + 1)}>Próxima &gt;</button>
      </div>
    </div>
  );
}
